import style from "./index.module.scss"
import template from "./index.html"
import {USDollar} from "../../utils/util"

export default class Table extends HTMLElement {
  _column
  _data
  set column(value) {
    this._column = value
    this.render()
  }
  get column() {
    return this._column
  }
  set data(value) {
    this._data = value
    this.render()
  }
  get data() {
    return this._data
  }
  constructor() {
    super();
    const sheet = document.createElement("style")
    sheet.innerHTML = style 
    this.innerHTML = template
    this.appendChild(sheet)
  }
  static get observedAttributes() {
    return ['column', 'data'];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
  }
  disconnectedCallback() {
  }
  renderHeader = ({column, theadRow}) => {
    theadRow.innerHTML = ""
    let headerRowString = ""
    column.forEach(c => {
      const className = ["principle", "interest", "balance", "year"].includes(c.name) ? "number" : ""
      headerRowString += `
        <th class=${className}>
          <div class="th-container">
            <button>${c.label}
              <div class="icon-container">
              <svg name="down" xmlns="http://www.w3.org/2000/svg" height="16" viewBox="0 -960 960 960" width="16"><path d="M480-360 280-560h400L480-360Z"/></svg>
              <svg name="up" xmlns="http://www.w3.org/2000/svg" height="16" viewBox="0 -960 960 960" width="16"><path d="m280-400 200-200 200 200H280Z"/></svg>
              </div>
            </button>
          <div>
        </th>
      `  
    });
    theadRow.innerHTML = headerRowString
  }
  renderBody = ({data, tbody}) => {
    tbody.innerHTML = ""
    let contentString = ""
    data.forEach(d => {
      contentString += "<tr>"
      for (const key in d) {
        const isDollar = ["principle", "interest", "balance"].includes(key) ? "number" : ""
        const text = isDollar ? USDollar.format(Math.floor(d[key])) : d[key]
        contentString += `<td data-value="${d[key]}">
          <div class="cell">${text}</div>
        </td>`
      }
      contentString += "</tr>"
    });
    tbody.innerHTML = contentString
  }
  render = () => {
    const table = this.querySelector(".table")
    const theadRow = this.querySelector("thead tr")
    const tbody = this.querySelector("tbody")
    this.column && this.renderHeader({column: this.column, theadRow})
    this.data && this.renderBody({data: this.data, tbody})
    new SortableTable(table)
  }
}


class SortableTable {
  tableNode
  columnHeaders
  sortColumns
  constructor(tableNode) {
    this.tableNode = tableNode;

    this.columnHeaders = Array.from(tableNode.querySelectorAll('thead th'))

    this.sortColumns = [];

    for (let i = 0; i < this.columnHeaders.length; i++) {
      const ch = this.columnHeaders[i];
      const buttonNode = ch.querySelector('button');
      if (buttonNode) {
        this.sortColumns.push(i);
        buttonNode.setAttribute('data-column-index', i);
        buttonNode.addEventListener('click', this.handleClick.bind(this));
      }
    }

    this.tableNode.classList.add('show-unsorted-icon');
  }

  setColumnHeaderSort(columnIndex) {
    if (typeof columnIndex === 'string') {
      columnIndex = parseInt(columnIndex);
    }

    for (let i = 0; i < this.columnHeaders.length; i++) {
      const ch = this.columnHeaders[i];
      const buttonNode = ch.querySelector('button');
      if (i === columnIndex) {
        const value = ch.getAttribute('aria-sort');
        if (value === 'descending') {
          ch.setAttribute('aria-sort', 'ascending');
          this.sortColumn(
            columnIndex,
            'ascending',
            ch.classList.contains('number')
          );
        } else {
          ch.setAttribute('aria-sort', 'descending');
          this.sortColumn(
            columnIndex,
            'descending',
            ch.classList.contains('number')
          );
        }
      } else {
        if (ch.hasAttribute('aria-sort') && buttonNode) {
          ch.removeAttribute('aria-sort');
        }
      }
    }
  }

  sortColumn(columnIndex, sortValue, isNumber) {
    function compareValues(a, b) {
      if (sortValue === 'ascending') {
        if (a.value === b.value) {
          return 0;
        } else {
          if (isNumber) {
            return a.value - b.value;
          } else {
            return a.value < b.value ? -1 : 1;
          }
        }
      } else {
        if (a.value === b.value) {
          return 0;
        } else {
          if (isNumber) {
            return b.value - a.value;
          } else {
            return a.value > b.value ? -1 : 1;
          }
        }
      }
    }

    if (typeof isNumber !== 'boolean') {
      isNumber = false;
    }

    const tbodyNode = this.tableNode.querySelector('tbody');
    const rowNodes = [];
    const dataCells = [];

    let rowNode = tbodyNode.firstElementChild;

    let index = 0;
    while (rowNode) {
      rowNodes.push(rowNode);
      const rowCells = rowNode.querySelectorAll('th, td');
      const dataCell = rowCells[columnIndex];

      const data = {};
      data.index = index;
      data.value = dataCell.getAttribute("data-value").trim()
      if (isNumber) {
        data.value = parseFloat(dataCell.getAttribute("data-value"));
      }
      dataCells.push(data);
      rowNode = rowNode.nextElementSibling;
      index += 1;
    }

    dataCells.sort(compareValues);

    // remove rows
    while (tbodyNode.firstChild) {
      tbodyNode.removeChild(tbodyNode.lastChild);
    }

    // add sorted rows
    for (let i = 0; i < dataCells.length; i += 1) {
      tbodyNode.appendChild(rowNodes[dataCells[i].index]);
    }
  }

  /* EVENT HANDLERS */

  handleClick(event) {
    const tgt = event.currentTarget;
    this.setColumnHeaderSort(tgt.getAttribute('data-column-index'));
  }

  handleOptionChange(event) {
    const tgt = event.currentTarget;

    if (tgt.checked) {
      this.tableNode.classList.add('show-unsorted-icon');
    } else {
      this.tableNode.classList.remove('show-unsorted-icon');
    }
  }
}